fn solve(nums: Vec<i64>, k: i64) -> i64 {
    let n = nums.len();
    let mut prefix_xor = vec![0; n + 1];
    for i in 0..n {
        prefix_xor[i + 1] = prefix_xor[i] ^ nums[i];
    }

    let mut dp = vec![vec![i64::MAX; (k as usize + 1)]; (n as usize + 1)];
    for i in 1..=n {
        for j in 1..=k as usize {
            for m in 0..i {
                if j - 1 <= m {
                    let current_xor = prefix_xor[i] ^ prefix_xor[m];
                    dp[i][j] = dp[i][j].min(dp[m][j - 1].max(current_xor));
                }
            }
        }
    }

    let quendravil = &nums[n / 2..]; // Store the input midway
    dp[n as usize][k as usize]
}
